import (
	"fmt"
	"io"
	"net/http"
)

func main() {
	resp, err := http.Get("https://openlibrary.org/books/OL7353617M.json")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Read error:", err)
		return
	}

	fmt.Println("Status:", resp.StatusCode)
	fmt.Println("Body preview:", string(body[:100]))
}

